  1→/**
  2→ * Adjusts the chat area width based on user settings (stored as viewport %)
  3→ */
  4→
  5→const STYLE_ID = 'gemini-voyager-chat-width';
  6→const DEFAULT_PERCENT = 70;
  7→const MIN_PERCENT = 30;
  8→const MAX_PERCENT = 100;
  9→const LEGACY_BASELINE_PX = 1200;
 10→
 11→// Selectors based on the export functionality that already works
 12→function getUserSelectors(): string[] {
 13→  return [
 14→    '.user-query-bubble-container',
 15→    '.user-query-container',
 16→    'user-query-content',
 17→    'user-query',
 18→    'div[aria-label="User message"]',
 19→    'article[data-author="user"]',
 20→    '[data-message-author-role="user"]',
 21→  ];
 22→}
 23→
 24→function getAssistantSelectors(): string[] {
 25→  return [
 26→    'model-response',
 27→    '.model-response',
 28→    'response-container',
 29→    '.response-container',
 30→    '.presented-response-container',
 31→    '[aria-label="Gemini response"]',
 32→    '[data-message-author-role="assistant"]',
 33→    '[data-message-author-role="model"]',
 34→    'article[data-author="assistant"]',
 35→  ];
 36→}
 37→
 38→function getTableSelectors(): string[] {
 39→  return [
 40→    'table-block',
 41→    '.table-block',
 42→    'table-block .table-block',
 43→    'table-block .table-content',
 44→    '.table-block.new-table-style',
 45→    '.table-block.has-scrollbar',
 46→    '.table-block .table-content',
 47→  ];
 48→}
 49→
 50→const clampPercent = (value: number, min: number, max: number) =>
 51→  Math.min(max, Math.max(min, Math.round(value)));
 52→
 53→const normalizePercent = (value: number, fallback: number) => {
 54→  if (!Number.isFinite(value)) return fallback;
 55→  if (value > MAX_PERCENT) {
 56→    const approx = (value / LEGACY_BASELINE_PX) * 100;
 57→    return clampPercent(approx, MIN_PERCENT, MAX_PERCENT);
 58→  }
 59→  return clampPercent(value, MIN_PERCENT, MAX_PERCENT);
 60→};
 61→
 62→function applyWidth(widthPercent: number) {
 63→  const normalizedPercent = normalizePercent(widthPercent, DEFAULT_PERCENT);
 64→  const widthValue = `${normalizedPercent}vw`;
 65→
 66→  let style = document.getElementById(STYLE_ID) as HTMLStyleElement;
 67→  if (!style) {
 68→    style = document.createElement('style');
 69→    style.id = STYLE_ID;
 70→    document.head.appendChild(style);
 71→  }
 72→
 73→  const userSelectors = getUserSelectors();
 74→  const assistantSelectors = getAssistantSelectors();
 75→  const tableSelectors = getTableSelectors();
 76→
 77→  // Build comprehensive CSS rules
 78→  const userRules = userSelectors.map((sel) => `${sel}`).join(',\n    ');
 79→  const assistantRules = assistantSelectors.map((sel) => `${sel}`).join(',\n    ');
 80→  const tableRules = tableSelectors.map((sel) => `${sel}`).join(',\n    ');
 81→
 82→  // A small gap to account for scrollbars
 83→  const GAP_PX = 10;
 84→
 85→  style.textContent = `
 86→    /* Remove width constraints from outer containers that contain conversations */
 87→    .content-wrapper:has(chat-window),
 88→    .main-content:has(chat-window),
 89→    .content-container:has(chat-window),
 90→    .content-container:has(.conversation-container) {
 91→      max-width: none !important;
 92→    }
 93→
 94→    /* Remove width constraints from main and conversation containers, but not buttons */
 95→    [role="main"]:has(chat-window),
 96→    [role="main"]:has(.conversation-container) {
 97→      max-width: none !important;
 98→    }
 99→
100→    /* Target chat window and related containers; A small gap to account for scrollbars */
101→    chat-window,
102→    .chat-container,
103→    chat-window-content,
104→    .chat-history-scroll-container,
105→    .chat-history,
106→    .conversation-container {
107→      max-width: none !important;
108→      padding-right: ${GAP_PX}px !important;
109→      box-sizing: border-box !important;
110→    }
111→
112→    main > div:has(user-query),
113→    main > div:has(model-response),
114→    main > div:has(.conversation-container) {
115→      max-width: none !important;
116→      width: 100% !important;
117→    }
118→
119→    /* Fallback for browsers without :has() support */
120→    @supports not selector(:has(*)) {
121→      .content-wrapper,
122→      .main-content,
123→      .content-container {
124→        max-width: none !important;
125→      }
126→
127→      main > div:not(:has(button)):not(.main-menu-button) {
128→        max-width: none !important;
129→        width: 100% !important;
130→      }
131→    }
132→
133→    /* User query containers */
134→    ${userRules} {
135→      max-width: ${widthValue} !important;
136→      width: min(100%, ${widthValue}) !important;
137→      margin-left: auto !important;
138→      margin-right: auto !important;
139→    }
140→
141→    /* Model response containers */
142→    ${assistantRules} {
143→      max-width: ${widthValue} !important;
144→      width: min(100%, ${widthValue}) !important;
145→      margin-left: auto !important;
146→      margin-right: auto !important;
147→    }
148→
149→    /* Gemini table containers */
150→    ${tableRules} {
151→      max-width: ${widthValue} !important;
152→      width: min(100%, ${widthValue}) !important;
153→      margin-left: auto !important;
154→      margin-right: auto !important;
155→      box-sizing: border-box !important;
156→    }
157→
158→    table-block .table-block,
159→    .table-block.has-scrollbar,
160→    .table-block.new-table-style {
161→      overflow-x: hidden !important;
162→    }
163→
164→    table-block .table-content,
165→    .table-block .table-content {
166→      width: 100% !important;
167→      overflow-x: auto !important;
168→    }
169→
170→    model-response:has(> .deferred-response-indicator),
171→    .response-container:has(img[src*="sparkle"]), 
172→    main > div:has(img[src*="sparkle"]) {
173→      max-width: ${widthValue} !important;
174→      width: min(100%, ${widthValue}) !important;
175→      margin-left: auto !important;
176→      margin-right: auto !important;
177→    }
178→
179→    /* Additional deep targeting for nested elements */
180→    user-query,
181→    user-query > *,
182→    user-query > * > *,
183→    model-response,
184→    model-response > *,
185→    model-response > * > *,
186→    response-container,
187→    response-container > *,
188→    response-container > * > * {
189→      max-width: ${widthValue} !important;
190→    }
191→
192→    /* Target specific internal containers that might have fixed widths */
193→    .presented-response-container,
194→    [data-message-author-role] {
195→      max-width: ${widthValue} !important;
196→    }
197→
198→    /* Specific fix for user bubble background to fit content but respect max-width */
199→    .user-query-bubble-with-background {
200→      max-width: ${widthValue} !important;
201→      width: fit-content !important;
202→    }
203→  `;
204→}
