206→function removeStyles() {
207→  const style = document.getElementById(STYLE_ID);
208→  if (style) {
209→    style.remove();
210→  }
211→}
212→
213→export function startChatWidthAdjuster() {
214→  let currentWidthPercent = DEFAULT_PERCENT;
215→
216→  // Load initial width (%), migrating legacy px values when seen
217→  chrome.storage?.sync?.get({ geminiChatWidth: DEFAULT_PERCENT }, (res) => {
218→    const storedWidth = res?.geminiChatWidth;
219→    const numericStoredWidth = typeof storedWidth === 'number' ? storedWidth : DEFAULT_PERCENT;
220→    const normalized = normalizePercent(numericStoredWidth, DEFAULT_PERCENT);
221→    currentWidthPercent = normalized;
222→    applyWidth(currentWidthPercent);
223→
224→    if (typeof storedWidth === 'number' && storedWidth !== normalized) {
225→      try {
226→        chrome.storage?.sync?.set({ geminiChatWidth: normalized });
227→      } catch (e) {
228→        console.warn('[Gemini Voyager] Failed to migrate chat width to %:', e);
229→      }
230→    }
231→  });
232→
233→  // Listen for changes from storage
234→  const storageChangeHandler = (
235→    changes: Record<string, chrome.storage.StorageChange>,
236→    area: string,
237→  ) => {
238→    if (area === 'sync' && changes.geminiChatWidth) {
239→      const newWidth = changes.geminiChatWidth.newValue;
240→      if (typeof newWidth === 'number') {
241→        const normalized = normalizePercent(newWidth, DEFAULT_PERCENT);
242→        currentWidthPercent = normalized;
243→        applyWidth(currentWidthPercent);
244→
245→        if (normalized !== newWidth) {
246→          try {
247→            chrome.storage?.sync?.set({ geminiChatWidth: normalized });
248→          } catch (e) {
249→            console.warn('[Gemini Voyager] Failed to migrate chat width to % on change:', e);
250→          }
251→        }
252→      }
253→    }
254→  };
255→
256→  chrome.storage?.onChanged?.addListener(storageChangeHandler);
257→
258→  // Re-apply styles when DOM changes (for dynamic content)
259→  // Use debouncing and cache the width to avoid storage reads
260→  let debounceTimer: number | null = null;
261→  const observer = new MutationObserver(() => {
262→    if (debounceTimer !== null) {
263→      clearTimeout(debounceTimer);
264→    }
265→    debounceTimer = window.setTimeout(() => {
266→      // Use cached width instead of reading from storage
267→      applyWidth(currentWidthPercent);
268→      debounceTimer = null;
269→    }, 200);
270→  });
271→
272→  // Observe the main conversation area for changes
273→  const main = document.querySelector('main');
274→  if (main) {
275→    observer.observe(main, {
276→      childList: true,
277→      subtree: true,
278→    });
279→  }
280→
281→  // Clean up on unload to prevent memory leaks
282→  window.addEventListener(
283→    'beforeunload',
284→    () => {
285→      observer.disconnect();
286→      removeStyles();
287→      // Remove storage listener
288→      try {
289→        chrome.storage?.onChanged?.removeListener(storageChangeHandler);
290→      } catch (e) {
291→        console.error('[Gemini Voyager] Failed to remove storage listener on unload:', e);
292→      }
293→    },
294→    { once: true },
295→  );
296→}
