 1→import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
 2→
 3→const STYLE_ID = 'gemini-voyager-chat-width';
 4→const STORAGE_KEY = 'geminiChatWidth';
 5→
 6→type StorageChangeListener = (
 7→  changes: Record<string, chrome.storage.StorageChange>,
 8→  area: string,
 9→) => void;
10→
11→function getInjectedStyle(): HTMLStyleElement {
12→  const style = document.getElementById(STYLE_ID);
13→  expect(style).not.toBeNull();
14→  return style as HTMLStyleElement;
15→}
16→
17→function expectTableRuleWidth(styleText: string, widthVw: number): void {
18→  const escapedWidth = widthVw.toString().replace('.', '\\.');
19→  const tableRulePattern = new RegExp(
20→    String.raw`\/\* Gemini table containers \*\/[\s\S]*table-block,[\s\S]*\.table-block,[\s\S]*\.table-block \.table-content[\s\S]*\{[\s\S]*max-width: ${escapedWidth}vw !important;[\s\S]*width: min\(100%, ${escapedWidth}vw\) !important;`,
21→  );
22→  expect(styleText).toMatch(tableRulePattern);
23→}
24→
25→function expectSingleTableScrollbarRules(styleText: string): void {
26→  expect(styleText).toContain('.table-block.has-scrollbar');
27→  expect(styleText).toContain('.table-block.new-table-style');
28→  expect(styleText).toContain('overflow-x: hidden !important;');
29→  expect(styleText).toContain('.table-block .table-content');
30→  expect(styleText).toContain('overflow-x: auto !important;');
