33→describe('chatWidth', () => {
34→  let storageChangeListeners: StorageChangeListener[];
35→
36→  beforeEach(() => {
37→    vi.resetModules();
38→    vi.clearAllMocks();
39→
40→    document.head.innerHTML = '';
41→    document.body.innerHTML = '<main></main>';
42→
43→    storageChangeListeners = [];
44→
45→    (chrome.storage.sync.get as unknown as ReturnType<typeof vi.fn>).mockImplementation(
46→      (_defaults: Record<string, unknown>, callback: (value: Record<string, unknown>) => void) => {
47→        callback({ [STORAGE_KEY]: 85 });
48→      },
49→    );
50→
51→    (
52→      chrome.storage.onChanged.addListener as unknown as ReturnType<typeof vi.fn>
