61→
62→  it('applies widescreen rules to Gemini table blocks', async () => {
63→    const { startChatWidthAdjuster } = await import('../index');
64→    startChatWidthAdjuster();
65→
66→    const styleText = getInjectedStyle().textContent ?? '';
67→
68→    expectTableRuleWidth(styleText, 85);
69→    expect(styleText).toContain('table-block .table-block');
70→    expect(styleText).toContain('.table-block.has-scrollbar');
71→    expect(styleText).toContain('.table-block.new-table-style');
72→    expect(styleText).toContain('.table-block .table-content');
73→    expectSingleTableScrollbarRules(styleText);
74→  });
75→
76→  it('updates table widescreen rules when width setting changes', async () => {
77→    const { startChatWidthAdjuster } = await import('../index');
78→    startChatWidthAdjuster();
79→
80→    expect(storageChangeListeners.length).toBeGreaterThan(0);
81→
82→    storageChangeListeners[0]({ [STORAGE_KEY]: { oldValue: 85, newValue: 92 } }, 'sync');
83→
84→    const styleText = getInjectedStyle().textContent ?? '';
85→    expectTableRuleWidth(styleText, 92);
86→    expect(styleText).toContain('table-block .table-content');
87→    expectSingleTableScrollbarRules(styleText);
88→  });
89→});
